(function(){
  const svg=$('#lc-svg'), slider=$('#lc-t'), tval=$('#lc-tval'), out=$('#lc-out');
  const W=620,H=320,cx=310,cy=160,R=120;
  function draw(){
    svg.innerHTML='';
    const t = parseFloat(slider.value);
    // axes
    svg.appendChild(SVG('line',{x1:40,y1:cy,x2:W-40,y2:cy,stroke:'var(--line)','stroke-width':1}));
    svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)','stroke-width':1}));
    // circle
    svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'none',stroke:'var(--blue)','stroke-width':2}));
    // line y = t  (world y)  mapped to pixel y = cy - R*t
    const py = cy - R*t;
    svg.appendChild(SVG('line',{x1:40,y1:py,x2:W-40,y2:py,stroke:'var(--yellow)','stroke-width':2}));
    // intersections: x = ±sqrt(1-t^2)
    const disc = 1 - t*t;
    let points=[];
    let msg='';
    if(disc > 1e-6){
      const xr = Math.sqrt(disc);
      points.push([xr,t],[-xr,t]);
      msg = `two real points: (${xr.toFixed(3)}, ${t.toFixed(3)})  and  (${(-xr).toFixed(3)}, ${t.toFixed(3)})\n`
          + `intersection count: 2  (matches $1 \\cdot 2 = 2$)`;
    } else if(Math.abs(disc) < 1e-6){
      points.push([0,t]);
      msg = `tangent: one real point (0, ${t.toFixed(3)}) — but counted with multiplicity 2.\n`
          + `the line and circle share the tangent direction here.`;
    } else {
      const c1 = Math.sqrt(-disc);
      msg = `no real intersection.\n`
          + `over $\\mathbb{C}$: two points at  x = ±${c1.toFixed(3)}i, y = ${t.toFixed(3)}.\n`
          + `intersection count (in $\\mathbb{C}$): 2.`;
    }
    for(const [x,y] of points){
      const px = cx + R*x, pyy = cy - R*y;
      const col = (Math.abs(disc) < 1e-6) ? 'var(--pink)' : 'var(--green)';
      svg.appendChild(SVG('circle',{cx:px,cy:pyy,r:6,fill:col,stroke:'#fff','stroke-width':1.2}));
      if(Math.abs(disc) < 1e-6){
        const t2=SVG('text',{x:px+10,y:pyy-8,'font-size':11,fill:'var(--pink)'});
        t2.textContent='mult 2';
        svg.appendChild(t2);
      }
    }
    tval.textContent = `t = ${t.toFixed(2)}`;
    out.textContent = msg;
  }
  slider.addEventListener('input',draw);
  draw();
})();

