const sel=$('#hm-pick'), out=$('#hm-out');
const DATA = {
  line: {
    f:'f(x,y) = x + y - 1',
    F:'F(X,Y,Z) = X + Y - Z',
    deg:1,
    infPoly:'F(X,Y,0) = X + Y',
    infZeros:'[-1 : 1 : 0]   — one point at infinity (the direction (1,-1))',
  },
  par: {
    f:'f(x,y) = y - x^2',
    F:'F(X,Y,Z) = YZ - X^2',
    deg:2,
    infPoly:'F(X,Y,0) = -X^2',
    infZeros:'[0 : 1 : 0]   — one point, but as a DOUBLE zero of -X^2 (multiplicity 2 at infinity)',
  },
  circ: {
    f:'f(x,y) = x^2 + y^2 - 1',
    F:'F(X,Y,Z) = X^2 + Y^2 - Z^2',
    deg:2,
    infPoly:'F(X,Y,0) = X^2 + Y^2',
    infZeros:'[1 : i : 0]  and  [1 : -i : 0]   — the "circular points" (complex conjugate)',
  },
  cub: {
    f:'f(x,y) = y^2 - x^3 - 1',
    F:'F(X,Y,Z) = Y^2 Z - X^3 - Z^3',
    deg:3,
    infPoly:'F(X,Y,0) = -X^3',
    infZeros:'[0 : 1 : 0]   — single point but as a triple zero (inflection at infinity on the cubic)',
  }
};
function update(){
  const d = DATA[sel.value];
  out.textContent =
    `affine:   ${d.f}\n`+
    `homogenize (degree ${d.deg}):\n   ${d.F}\n\n`+
    `points at infinity  (set Z = 0):\n   ${d.infPoly}\n   zeros: ${d.infZeros}`;
}
sel.addEventListener('change',update); update();

