(function(){
  const fSel=$('#mc-f'), gSel=$('#mc-g'), svg=$('#mc-svg'), out=$('#mc-out');
  const W=620,H=320,cx=310,cy=160,S=80; // pixels per unit

  // evaluator for a small set of curves
  const FNS = {
    'x':        (x,y)=>x,
    'y':        (x,y)=>y,
    'y-x':      (x,y)=>y-x,
    'y-x2':     (x,y)=>y-x*x,
    'y+x2':     (x,y)=>y+x*x,
    'y2-x3':    (x,y)=>y*y - x*x*x,
    'x2-y3':    (x,y)=>x*x - y*y*y,
  };
  const LABEL = {
    'x':'x','y':'y','y-x':'y - x','y-x2':'y - x^2','y+x2':'y + x^2',
    'y2-x3':'y^2 - x^3','x2-y3':'x^2 - y^3',
  };
  // precomputed multiplicities at origin; each entry keyed by sorted "f|g"
  const MULT = {
    'x|y':     {I:1, note:'transverse crossing of the two coordinate axes.'},
    'x|y-x':   {I:1, note:'two lines meeting transversally through 0.'},
    'y|y-x':   {I:1, note:'two distinct lines through 0, transverse.'},
    'y|y-x2':  {I:2, note:'the x-axis is TANGENT to the parabola at 0 — multiplicity 2.'},
    'x|y-x2':  {I:1, note:'the y-axis cuts the parabola transversally.'},
    'y-x|y-x2':{I:1, note:'the line y=x hits the parabola at 0 and at (1,1). Each is simple.'},
    'y|y+x2':  {I:2, note:'tangent of opposite curvature — still double contact.'},
    'y|y2-x3': {I:3, note:'the x-axis meets the cusp y^2 = x^3 with multiplicity 3 — triple contact.'},
    'x|y2-x3': {I:2, note:'the y-axis meets the cusp in a double point (the cusp itself).'},
    'y-x|y2-x3':{I:1, note:'the line y=x meets y^2=x^3 transversally at origin (and at (1,1)).'},
    'y-x2|y2-x3':{I:4, note:'parabola vs. cusp: a rare quartic contact at origin.'},
    'y-x2|y+x2':{I:2, note:'two parabolas sharing a tangent line (the x-axis).'},
    'y2-x3|x2-y3':{I:4, note:'two cusps with a common tangent axis — complicated local contact.'},
    'y-x2|x2-y3':{I:2, note:'contact of order 2 at origin.'},
  };

  function key(a,b){ return [a,b].sort().join('|'); }

  function draw(){
    svg.innerHTML='';
    // axes
    svg.appendChild(SVG('line',{x1:20,y1:cy,x2:W-20,y2:cy,stroke:'var(--line)','stroke-width':1}));
    svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)','stroke-width':1}));
    // plot f=0 and g=0 using marching-squares-ish sampling (rough but adequate)
    const f = FNS[fSel.value], g = FNS[gSel.value];
    plotCurve(f,'var(--blue)');
    plotCurve(g,'var(--yellow)');
    // highlight origin
    svg.appendChild(SVG('circle',{cx,cy,r:7,fill:'var(--pink)',stroke:'#fff','stroke-width':1.2}));
    const t = SVG('text',{x:cx+10,y:cy-10,'font-size':11,fill:'var(--pink)'});
    t.textContent='P = (0,0)';
    svg.appendChild(t);

    const k = key(fSel.value, gSel.value);
    const data = MULT[k];
    let msg;
    if(fSel.value === gSel.value){
      msg = `f = g = ${LABEL[fSel.value]}: not in general position (common component); Bezout doesn't apply.`;
    } else if(data){
      msg = `f = ${LABEL[fSel.value]}\n`+
            `g = ${LABEL[gSel.value]}\n\n`+
            `I_P(f,g) = ${data.I}\n`+
            `${data.note}`;
    } else {
      msg = `f = ${LABEL[fSel.value]}\n`+
            `g = ${LABEL[gSel.value]}\n\n`+
            `(mult not tabulated for this pair — pick another)`;
    }
    out.textContent = msg;
  }

  function plotCurve(fn,color){
    const N=180, step=0.03;
    const pts=[];
    for(let i=-N;i<=N;i++){
      for(let j=-N;j<=N;j++){
        const x=i*step, y=j*step;
        const v = fn(x,y);
        if(Math.abs(v) < 0.018 + 0.02*(Math.abs(x)+Math.abs(y))){
          pts.push([cx+x*S, cy-y*S]);
        }
      }
    }
    for(const [px,py] of pts){
      svg.appendChild(SVG('circle',{cx:px,cy:py,r:1.4,fill:color,opacity:0.7}));
    }
  }

  fSel.addEventListener('change',draw);
  gSel.addEventListener('change',draw);
  draw();
})();

