(function(){
  const sel=$('#rs-ex'), svg=$('#rs-svg'), out=$('#rs-out');
  const DATA = {
    A: {
      f:'f(y) = y - 1',
      g:'g(y) = y - x',
      res:'Res_y(f,g) = -1 + x = x - 1',
      roots:'x = 1',
      note:'f and g share a root in y iff x = 1. Geometrically: two horizontal lines; they meet only at x=1 where both equal y=1.'
    },
    B: {
      f:'f(y) = y^2 - x',
      g:'g(y) = y - x',
      res:'Res_y(f,g) = x^2 - x = x(x-1)',
      roots:'x = 0, x = 1',
      note:'parabola y = sqrt(x) meets line y = x at (0,0) and (1,1). Each is simple.'
    },
    C: {
      f:'f(y) = y^2 - x',
      g:'g(y) = y^2 + x',
      res:'Res_y(f,g) = (2x)^2 = 4x^2',
      roots:'x = 0 (double)',
      note:'two parabolas meeting at origin — x=0 appears with MULTIPLICITY 2 in the resultant, reflecting I_P = 2.'
    },
    D: {
      f:'f(y) = y^3 - x',
      g:'g(y) = y - x^2',
      res:'Res_y(f,g) = x^6 - x',
      roots:'x = 0 and x^5 = 1 (five 5th roots of unity)',
      note:'cubic vs. parabola: one root at x=0, five roots coming from a Mobius-style degree count. 1·3 + ... = 6 total.'
    },
  };
  function draw(){
    svg.innerHTML='';
    const d = DATA[sel.value];
    // visualise the resultant-polynomial roots on an x-axis
    svg.appendChild(SVG('line',{x1:40,y1:170,x2:580,y2:170,stroke:'var(--line)','stroke-width':1}));
    const xMin=-1.5, xMax=2.5;
    function toPx(x){ return 40 + (x - xMin) * 540/(xMax-xMin); }
    // ticks
    for(let v=-1;v<=2;v++){
      svg.appendChild(SVG('line',{x1:toPx(v),y1:165,x2:toPx(v),y2:175,stroke:'var(--mute)'}));
      const t=SVG('text',{x:toPx(v),y:190,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
      t.textContent=String(v);
      svg.appendChild(t);
    }
    const tit = SVG('text',{x:310,y:40,'text-anchor':'middle','font-size':13,fill:'var(--blue)'});
    tit.textContent = d.res;
    svg.appendChild(tit);
    // marker roots
    const markers = {
      A: [{x:1,m:1}],
      B: [{x:0,m:1},{x:1,m:1}],
      C: [{x:0,m:2}],
      D: [{x:0,m:1},{x:1,m:1}],
    };
    for(const {x,m} of markers[sel.value]){
      const col = m>1? 'var(--pink)':'var(--green)';
      svg.appendChild(SVG('circle',{cx:toPx(x),cy:170,r:m>1?8:6,fill:col,stroke:'#fff','stroke-width':1.2}));
      if(m>1){
        const lab=SVG('text',{x:toPx(x),y:155,'text-anchor':'middle','font-size':11,fill:'var(--pink)'});
        lab.textContent = 'mult '+m;
        svg.appendChild(lab);
      }
    }
    out.textContent =
      `${d.f}\n${d.g}\n\n${d.res}\nroots of Res_y(f,g): ${d.roots}\n\n${d.note}`;
  }
  sel.addEventListener('change',draw); draw();
})();

