const a=$('#tc-a'), b=$('#tc-b'), h=$('#tc-h'), r=$('#tc-r');
const aval=$('#tc-aval'), bval=$('#tc-bval'), hval=$('#tc-hval'), rval=$('#tc-rval');
const svg=$('#tc-svg'), out=$('#tc-out');
const W=620,H=360,cx=310,cy=180,S=80;
function solve(A,B,H,R){
  // (x-H)^2 + y^2 = R^2   and   x^2/A^2 + y^2/B^2 = 1
  // ==> y^2 = R^2 - (x-H)^2  and  y^2 = B^2(1 - x^2/A^2)
  // equate: R^2 - (x-H)^2 = B^2 - B^2 x^2 / A^2
  // ==> (-1 + B^2/A^2) x^2 + 2H x + (R^2 - H^2 - B^2) = 0
  const p2 = -1 + B*B/(A*A);
  const p1 = 2*H;
  const p0 = R*R - H*H - B*B;
  // quartic total: each real x yields up to 2 y's
  let xs;
  if(Math.abs(p2) < 1e-8){
    if(Math.abs(p1) < 1e-8) xs=[]; else xs=[-p0/p1];
  } else {
    const disc = p1*p1 - 4*p2*p0;
    if(disc < -1e-6) xs=[];
    else if(disc < 1e-6) xs=[-p1/(2*p2)];
    else { const s=Math.sqrt(disc); xs=[(-p1+s)/(2*p2),(-p1-s)/(2*p2)]; }
  }
  const pts=[];
  for(const x of xs){
    const y2 = R*R - (x-H)*(x-H);
    if(y2 > 1e-6){
      const y=Math.sqrt(y2);
      pts.push([x,y]); pts.push([x,-y]);
    } else if(y2 > -1e-6){
      pts.push([x,0]);
    }
  }
  return pts;
}
