  svg.appendChild(SVG('circle',{cx:cx+HH*S,cy,r:R*S,fill:'none',stroke:'var(--yellow)','stroke-width':2}));
  // intersections
  const pts = solve(A,B,HH,R);
  for(const [x,y] of pts){
    svg.appendChild(SVG('circle',{cx:cx+x*S,cy:cy-y*S,r:5,fill:'var(--green)',stroke:'#fff','stroke-width':1.1}));
  }
  let msg;
