(function(){
  const svg=$('#pa-svg'), th=$('#pa-th'), shuf=$('#pa-shuffle'), out=$('#pa-out');
  const W=620,H=380,cx=310,cy=180,R=140;
  let angles=[10,60,110,170,230,290];
  function rotAll(d){ angles = angles.map(a => (a+d)%360); }
  function lineInter(p1,p2,p3,p4){
    // intersection of line p1-p2 with p3-p4
    const [x1,y1]=p1,[x2,y2]=p2,[x3,y3]=p3,[x4,y4]=p4;
    const den = (x1-x2)*(y3-y4) - (y1-y2)*(x3-x4);
    if(Math.abs(den) < 1e-8) return null;
    const t = ((x1-x3)*(y3-y4) - (y1-y3)*(x3-x4))/den;
    return [x1 + t*(x2-x1), y1 + t*(y2-y1)];
  }
  function draw(){
    svg.innerHTML='';
    // conic (circle)
    svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'none',stroke:'var(--blue)','stroke-width':2}));
    // compute six points
    const base = parseFloat(th.value);
    const A = angles.map(a => {
      const rad = (a + base)*Math.PI/180;
      return [cx + R*Math.cos(rad), cy + R*Math.sin(rad)];
    });
    // dots + labels
    A.forEach((p,i)=>{
      svg.appendChild(SVG('circle',{cx:p[0],cy:p[1],r:5,fill:'var(--yellow)',stroke:'#fff','stroke-width':1}));
      const t=SVG('text',{x:p[0]+10,y:p[1]-10,'font-size':11,fill:'var(--yellow)'});
      t.textContent = String(i+1);
      svg.appendChild(t);
    });
    // hexagon sides 1-2, 2-3, ..., 6-1
    for(let i=0;i<6;i++){
      const [u,v]=[A[i], A[(i+1)%6]];
      svg.appendChild(SVG('line',{x1:u[0],y1:u[1],x2:v[0],y2:v[1],stroke:'var(--violet)','stroke-width':1,opacity:0.8}));
    }
    // the three opposite-side intersection points:
    //   (1-2) ∩ (4-5),  (2-3) ∩ (5-6),  (3-4) ∩ (6-1)
    const opps = [[0,1,3,4],[1,2,4,5],[2,3,5,0]];
    const ips=[];
    for(const [a1,a2,b1,b2] of opps){
      // extend each side to a long line for drawing
      const sideA1=A[a1], sideA2=A[a2], sideB1=A[b1], sideB2=A[b2];
      // draw extended (dashed) lines
      const ext = (p,q)=>{
        const dx=q[0]-p[0], dy=q[1]-p[1];
        return [[p[0]-1.2*dx,p[1]-1.2*dy],[q[0]+1.2*dx,q[1]+1.2*dy]];
      };
      const eA=ext(sideA1,sideA2), eB=ext(sideB1,sideB2);
      svg.appendChild(SVG('line',{x1:eA[0][0],y1:eA[0][1],x2:eA[1][0],y2:eA[1][1],
        stroke:'var(--violet)','stroke-width':0.8,'stroke-dasharray':'3 3',opacity:0.6}));
      svg.appendChild(SVG('line',{x1:eB[0][0],y1:eB[0][1],x2:eB[1][0],y2:eB[1][1],
        stroke:'var(--violet)','stroke-width':0.8,'stroke-dasharray':'3 3',opacity:0.6}));
      const ip = lineInter(sideA1,sideA2,sideB1,sideB2);
      if(ip) ips.push(ip);
    }
    // Pascal line through the three intersections
    let msg;
    if(ips.length === 3){
      for(const ip of ips){
        svg.appendChild(SVG('circle',{cx:ip[0],cy:ip[1],r:6,fill:'var(--pink)',stroke:'#fff','stroke-width':1.2}));
      }
      // fit a line through ips[0] and ips[2]; check ips[1] collinearity
      const [p,q,rr] = ips;
      const d = (q[0]-p[0])*(rr[1]-p[1]) - (q[1]-p[1])*(rr[0]-p[0]);
      // draw line through p and rr extended
      const dx=rr[0]-p[0], dy=rr[1]-p[1];
      svg.appendChild(SVG('line',{x1:p[0]-2*dx,y1:p[1]-2*dy,x2:rr[0]+2*dx,y2:rr[1]+2*dy,
        stroke:'var(--pink)','stroke-width':1.6}));
      msg = `three opposite-side intersections (pink): always collinear.\n`
          + `collinearity residual det ≈ ${d.toFixed(2)} (would be 0 in exact arithmetic).\n`
          + `the pink line is the PASCAL LINE of this inscribed hexagon.`;
    } else {
      msg = 'some opposite sides are parallel — Pascal line is at infinity.';
    }
    out.textContent = msg;
  }
  th.addEventListener('input',draw);
  shuf.addEventListener('click',()=>{
    angles = Array.from({length:6},()=>Math.random()*360).sort((a,b)=>a-b);
    draw();
  });
  draw();
})();

