(function(){
  const xp=$('#cu-xp'), xq=$('#cu-xq'), bp=$('#cu-bp'), bq=$('#cu-bq');
  const xpv=$('#cu-xpv'), xqv=$('#cu-xqv');
  const svg=$('#cu-svg'), out=$('#cu-out');
  const W=620,H=360,cx=180,cy=180,S=70;
  // curve: y^2 = x^3 - x + 1 (smooth elliptic)
  function f(x){ return x*x*x - x + 1; }
  function y_of(x, branch){
    const v = f(x);
    if(v < 0) return null;
    return branch*Math.sqrt(v);
  }
  function cubicRootSum(slope,inter){
    // line y = m x + c meets y^2 = x^3 - x + 1
    // ==> x^3 - x + 1 - (mx+c)^2 = 0
    // ==> x^3 - m^2 x^2 - (1 + 2mc) x + (1 - c^2) = 0
    // sum of roots = m^2
    return slope*slope;
  }
  function draw(){
    svg.innerHTML='';
    // axes
    svg.appendChild(SVG('line',{x1:20,y1:cy,x2:W-20,y2:cy,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)'}));
    // cubic sampled
    const pathU=[], pathL=[];
    for(let i=0;i<=600;i++){
      const x = -2 + 4.5*i/600;
      const v = f(x);
      if(v < 0) continue;
      const yy = Math.sqrt(v);
      pathU.push([cx+x*S, cy-yy*S]);
      pathL.push([cx+x*S, cy+yy*S]);
    }
    const toD = (pts)=> pts.length? 'M'+pts.map(p=>p[0]+' '+p[1]).join(' L ') : '';
    svg.appendChild(SVG('path',{d:toD(pathU),fill:'none',stroke:'var(--blue)','stroke-width':2}));
    svg.appendChild(SVG('path',{d:toD(pathL),fill:'none',stroke:'var(--blue)','stroke-width':2}));

    const xP = parseFloat(xp.value), xQ = parseFloat(xq.value);
    const brP = parseInt(bp.value,10), brQ = parseInt(bq.value,10);
    xpv.textContent = 'xP='+xP.toFixed(2);
    xqv.textContent = 'xQ='+xQ.toFixed(2);
    const yP = y_of(xP, brP), yQ = y_of(xQ, brQ);
    let msg;
    if(yP === null || yQ === null){
      msg = 'one of the chosen x values is off the real curve — slide it back.';
      out.textContent = msg;
      return;
    }
    // plot P, Q
    const P=[cx+xP*S, cy-yP*S], Q=[cx+xQ*S, cy-yQ*S];
    svg.appendChild(SVG('circle',{cx:P[0],cy:P[1],r:6,fill:'var(--yellow)',stroke:'#fff','stroke-width':1}));
    svg.appendChild(SVG('circle',{cx:Q[0],cy:Q[1],r:6,fill:'var(--yellow)',stroke:'#fff','stroke-width':1}));
    svg.appendChild(SVG('text',{x:P[0]+10,y:P[1]-10,'font-size':12,fill:'var(--yellow)'})).textContent='P';
    svg.appendChild(SVG('text',{x:Q[0]+10,y:Q[1]-10,'font-size':12,fill:'var(--yellow)'})).textContent='Q';

    let slope, inter, xR, yR;
    if(Math.abs(xP - xQ) < 1e-3){
      // tangent line: y^2 = f(x) ==> 2 y y' = f'(x) ==> slope = f'(xP)/(2 yP)
      const fp = 3*xP*xP - 1;
      slope = fp / (2*yP);
      inter = yP - slope*xP;
      xR = slope*slope - 2*xP; // from cubic root sum
    } else {
      slope = (yQ - yP)/(xQ - xP);
      inter = yP - slope*xP;
      xR = slope*slope - xP - xQ;
    }
    yR = slope*xR + inter;
    // draw line (extended)
    const xL=-2.2, xH=2.8;
    svg.appendChild(SVG('line',{x1:cx+xL*S,y1:cy-(slope*xL+inter)*S,x2:cx+xH*S,y2:cy-(slope*xH+inter)*S,
      stroke:'var(--pink)','stroke-width':1.6}));
    svg.appendChild(SVG('circle',{cx:cx+xR*S,cy:cy-yR*S,r:6,fill:'var(--green)',stroke:'#fff','stroke-width':1.2}));
    svg.appendChild(SVG('text',{x:cx+xR*S+10,y:cy-yR*S-10,'font-size':12,fill:'var(--green)'})).textContent='R = −(P + Q)';

    msg = `P = (${xP.toFixed(3)}, ${yP.toFixed(3)})\n`
        + `Q = (${xQ.toFixed(3)}, ${yQ.toFixed(3)})\n`
        + `line through P,Q:  y = ${slope.toFixed(3)} x + ${inter.toFixed(3)}\n`
        + `bezout forces a THIRD intersection with the cubic:\n`
        + `R = (${xR.toFixed(3)}, ${yR.toFixed(3)})\n\n`
        + `the group law sends P + Q = −R  (reflect across x-axis).`;
    out.textContent = msg;
  }
  [xp,xq,bp,bq].forEach(e=>e.addEventListener('input',draw));
  draw();
})();

(function(){
  const xp=$('#cu-xp'), xq=$('#cu-xq'), bp=$('#cu-bp'), bq=$('#cu-bq');
  const xpv=$('#cu-xpv'), xqv=$('#cu-xqv');
  const svg=$('#cu-svg'), out=$('#cu-out');
  const W=620,H=360,cx=180,cy=180,S=70;
  // curve: y^2 = x^3 - x + 1 (smooth elliptic)
  function f(x){ return x*x*x - x + 1; }
  function y_of(x, branch){
    const v = f(x);
    if(v < 0) return null;
    return branch*Math.sqrt(v);
  }
  function cubicRootSum(slope,inter){
    // line y = m x + c meets y^2 = x^3 - x + 1
    // ==> x^3 - x + 1 - (mx+c)^2 = 0
    // ==> x^3 - m^2 x^2 - (1 + 2mc) x + (1 - c^2) = 0
    // sum of roots = m^2
    return slope*slope;
  }
  function draw(){
    svg.innerHTML='';
    // axes
    svg.appendChild(SVG('line',{x1:20,y1:cy,x2:W-20,y2:cy,stroke:'var(--line)'}));
    svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:H-20,stroke:'var(--line)'}));
    // cubic sampled
    const pathU=[], pathL=[];
    for(let i=0;i<=600;i++){
      const x = -2 + 4.5*i/600;
      const v = f(x);
      if(v < 0) continue;
      const yy = Math.sqrt(v);
      pathU.push([cx+x*S, cy-yy*S]);
      pathL.push([cx+x*S, cy+yy*S]);
    }
    const toD = (pts)=> pts.length? 'M'+pts.map(p=>p[0]+' '+p[1]).join(' L ') : '';
    svg.appendChild(SVG('path',{d:toD(pathU),fill:'none',stroke:'var(--blue)','stroke-width':2}));
    svg.appendChild(SVG('path',{d:toD(pathL),fill:'none',stroke:'var(--blue)','stroke-width':2}));

    const xP = parseFloat(xp.value), xQ = parseFloat(xq.value);
    const brP = parseInt(bp.value,10), brQ = parseInt(bq.value,10);
    xpv.textContent = 'xP='+xP.toFixed(2);
    xqv.textContent = 'xQ='+xQ.toFixed(2);
    const yP = y_of(xP, brP), yQ = y_of(xQ, brQ);
    let msg;
    if(yP === null || yQ === null){
      msg = 'one of the chosen x values is off the real curve — slide it back.';
      out.textContent = msg;
      return;
    }
    // plot P, Q
    const P=[cx+xP*S, cy-yP*S], Q=[cx+xQ*S, cy-yQ*S];
    svg.appendChild(SVG('circle',{cx:P[0],cy:P[1],r:6,fill:'var(--yellow)',stroke:'#fff','stroke-width':1}));
    svg.appendChild(SVG('circle',{cx:Q[0],cy:Q[1],r:6,fill:'var(--yellow)',stroke:'#fff','stroke-width':1}));
    svg.appendChild(SVG('text',{x:P[0]+10,y:P[1]-10,'font-size':12,fill:'var(--yellow)'})).textContent='P';
    svg.appendChild(SVG('text',{x:Q[0]+10,y:Q[1]-10,'font-size':12,fill:'var(--yellow)'})).textContent='Q';

    let slope, inter, xR, yR;
    if(Math.abs(xP - xQ) < 1e-3){
      // tangent line: y^2 = f(x) ==> 2 y y' = f'(x) ==> slope = f'(xP)/(2 yP)
      const fp = 3*xP*xP - 1;
      slope = fp / (2*yP);
      inter = yP - slope*xP;
      xR = slope*slope - 2*xP; // from cubic root sum
    } else {
      slope = (yQ - yP)/(xQ - xP);
      inter = yP - slope*xP;
      xR = slope*slope - xP - xQ;
    }
    yR = slope*xR + inter;
    // draw line (extended)
    const xL=-2.2, xH=2.8;
    svg.appendChild(SVG('line',{x1:cx+xL*S,y1:cy-(slope*xL+inter)*S,x2:cx+xH*S,y2:cy-(slope*xH+inter)*S,
      stroke:'var(--pink)','stroke-width':1.6}));
    svg.appendChild(SVG('circle',{cx:cx+xR*S,cy:cy-yR*S,r:6,fill:'var(--green)',stroke:'#fff','stroke-width':1.2}));
    svg.appendChild(SVG('text',{x:cx+xR*S+10,y:cy-yR*S-10,'font-size':12,fill:'var(--green)'})).textContent='R = −(P + Q)';

    msg = `P = (${xP.toFixed(3)}, ${yP.toFixed(3)})\n`
        + `Q = (${xQ.toFixed(3)}, ${yQ.toFixed(3)})\n`
        + `line through P,Q:  y = ${slope.toFixed(3)} x + ${inter.toFixed(3)}\n`
        + `bezout forces a THIRD intersection with the cubic:\n`
        + `R = (${xR.toFixed(3)}, ${yR.toFixed(3)})\n\n`
        + `the group law sends P + Q = −R  (reflect across x-axis).`;
    out.textContent = msg;
  }
  [xp,xq,bp,bq].forEach(e=>e.addEventListener('input',draw));
  draw();
})();
